import {
  ChangeDetectionStrategy,
  Component,
  computed,
  contentChildren,
  input,
  output,
  signal,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HbCommandItemComponent } from './command-item.component';
import {
  HB_COMMAND,
  type HbCommandContext,
  type HbCommandInputRef,
  type HbCommandItemRef,
} from './command.token';
import { commandVariants, type HbCommandSize } from './command.variants';

@Component({
  selector: 'hb-command',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: { '[class]': 'classes()', role: 'listbox', '[attr.data-slot]': "'command'" },
  providers: [{ provide: HB_COMMAND, useExisting: HbCommandComponent }],
  exportAs: 'hbCommand',
})
export class HbCommandComponent implements HbCommandContext {
  readonly hbSize = input<HbCommandSize>('md');
  readonly class = input<ClassValue>('');
  readonly hbSelect = output<unknown>();
  readonly hbCommandChange = output<string>();

  readonly query = signal('');
  readonly activeItem = signal<HbCommandItemRef | null>(null);
  protected readonly items = contentChildren(HbCommandItemComponent, { descendants: true });
  private inputRef: HbCommandInputRef | null = null;

  protected readonly classes = computed(() => cn(commandVariants(), this.class()));

  matchesFilter(label: string, keywords: readonly string[]): boolean {
    const q = this.query().trim().toLowerCase();
    if (!q) return true;
    return [label, ...keywords].join(' ').toLowerCase().includes(q);
  }
  readonly hasVisibleItems = computed(() => this.items().some((i) => i.matches()));
  private readonly enabled = computed(() =>
    this.items().filter((i) => i.matches() && !i.hbDisabled()),
  );

  isActive(item: HbCommandItemRef): boolean {
    return this.activeItem() === item;
  }
  setActive(item: HbCommandItemRef): void {
    this.activeItem.set(item);
  }
  registerInput(input: HbCommandInputRef): void {
    this.inputRef = input;
  }
  focusInput(): void {
    this.inputRef?.focus();
  }
  setQuery(value: string): void {
    this.query.set(value);
    this.hbCommandChange.emit(value);
    this.activeItem.set(this.enabled()[0] ?? null);
  }
  selectItem(item: HbCommandItemRef): void {
    if (item.hbDisabled()) return;
    this.hbSelect.emit(item.hbValue());
    item.hbSelect.emit(item.hbValue());
  }
  onKeydown(event: KeyboardEvent): void {
    const enabled = this.enabled();
    switch (event.key) {
      case 'ArrowDown':
        this.move(enabled, 1);
        break;
      case 'ArrowUp':
        this.move(enabled, -1);
        break;
      case 'Home':
        if (enabled.length) this.activeItem.set(enabled[0]);
        break;
      case 'End':
        if (enabled.length) this.activeItem.set(enabled[enabled.length - 1]);
        break;
      case 'Enter': {
        const active = this.activeItem();
        if (active) this.selectItem(active);
        break;
      }
      default:
        return;
    }
    event.preventDefault();
  }
  private move(enabled: HbCommandItemComponent[], delta: number): void {
    if (!enabled.length) return;
    const current = this.activeItem();
    const idx = current ? enabled.indexOf(current as HbCommandItemComponent) : -1;
    const next = Math.max(0, Math.min(enabled.length - 1, idx + delta));
    this.activeItem.set(enabled[next]);
    enabled[next].scrollIntoView();
  }
}

import { HbCommandComponent } from './command.component';
import { HbCommandDialogComponent } from './command-dialog.component';
import { HbCommandEmptyComponent } from './command-empty.component';
import { HbCommandFooterComponent } from './command-footer.component';
import { HbCommandGroupComponent } from './command-group.component';
import { HbCommandInputComponent } from './command-input.component';
import { HbCommandItemComponent } from './command-item.component';
import { HbCommandListComponent } from './command-list.component';
import { HbCommandSeparatorComponent } from './command-separator.component';
import { HbCommandShortcutComponent } from './command-shortcut.component';

export const HbCommandImports = [
  HbCommandComponent,
  HbCommandInputComponent,
  HbCommandListComponent,
  HbCommandEmptyComponent,
  HbCommandGroupComponent,
  HbCommandItemComponent,
  HbCommandSeparatorComponent,
  HbCommandShortcutComponent,
  HbCommandFooterComponent,
  HbCommandDialogComponent,
] as const;

import { InjectionToken } from '@angular/core';

import { type HbCommandSize } from './command.variants';

export interface HbCommandItemRef {
  matches(): boolean;
  hbDisabled(): boolean;
  hbValue(): unknown;
  hbSelect: { emit(value: unknown): void };
  scrollIntoView(): void;
}

export interface HbCommandInputRef {
  focus(): void;
}

export interface HbCommandContext {
  hbSize: () => HbCommandSize;
  query: () => string;
  hasVisibleItems: () => boolean;
  matchesFilter(label: string, keywords: readonly string[]): boolean;
  isActive(item: HbCommandItemRef): boolean;
  setActive(item: HbCommandItemRef): void;
  selectItem(item: HbCommandItemRef): void;
  registerInput(input: HbCommandInputRef): void;
  setQuery(value: string): void;
  onKeydown(event: KeyboardEvent): void;
}

export const HB_COMMAND = new InjectionToken<HbCommandContext>('HB_COMMAND');

import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '{{alias}}/utils';

export const commandVariants = cva(
  cn(
    'flex w-full flex-col overflow-hidden rounded-md border border-border bg-popover text-popover-foreground',
  ),
);

export const commandInputVariants = cva(
  cn(
    'flex w-full bg-transparent outline-none placeholder:text-muted-foreground',
    'disabled:cursor-not-allowed disabled:opacity-50',
  ),
  {
    variants: {
      size: { xs: 'h-8 text-xs', sm: 'h-9 text-sm', md: 'h-10 text-sm', lg: 'h-11 text-base', xl: 'h-12 text-base' },
    },
    defaultVariants: { size: 'md' },
  },
);

export const commandItemVariants = cva(
  cn(
    'relative flex cursor-default select-none items-center gap-2 rounded-sm px-2 outline-none',
    'data-[active=true]:bg-accent data-[active=true]:text-accent-foreground',
    'data-[disabled=true]:pointer-events-none data-[disabled=true]:opacity-50',
    '[&_ng-icon]:size-4 [&_ng-icon]:shrink-0 [&_ng-icon]:text-muted-foreground',
  ),
  {
    variants: {
      size: { xs: 'py-1 text-xs', sm: 'py-1.5 text-sm', md: 'py-1.5 text-sm', lg: 'py-2 text-base', xl: 'py-2.5 text-base' },
    },
    defaultVariants: { size: 'md' },
  },
);

export const commandGroupHeadingVariants = cva(
  'px-2 py-1.5 font-mono text-[11px] font-medium uppercase tracking-[0.08em] text-muted-foreground',
);
export const commandSeparatorVariants = cva('-mx-1 my-1 h-px bg-border');
export const commandShortcutVariants = cva('ml-auto font-mono text-xs tracking-widest text-muted-foreground');
export const commandEmptyVariants = cva('py-6 text-center text-sm text-muted-foreground');
export const commandFooterVariants = cva(
  'flex items-center gap-2 border-t border-border px-3 py-2 text-xs text-muted-foreground',
);

export type HbCommandSize = NonNullable<VariantProps<typeof commandInputVariants>['size']>;

